import React, { Component } from 'react';
import ProjectList from './../components/ProjectList';
import Sidebar from './../components/Sidebar';
import Test from './../pages/Test';

class Home extends Component {
  state = {
    projects: [
      {
        id: 1,
        name: 'Booklandia',
        desc: 'Website',
        img: 'img/works/booklandia.png',
        url: '',
      },
      {
        id: 2,
        name: 'TESDA Womens Center',
        desc: 'Website',
        img: 'img/works/twc.png',
      },
      {
        id: 3,
        name: 'Romblon Institute of Technology',
        desc: 'Website',
        img: 'img/works/fun-run.png',
      },
      {
        id: 4,
        name: 'Finest Aluminum Catalogue',
        desc: 'Design',
        img: 'img/works/finest-catalogue.png',
      },
      {
        id: 5,
        name: 'Finest Aluminum Brochure',
        desc: 'Design',
        img: 'img/works/finest-brochure.png',
      },
      {
        id: 6,
        name: 'P&G Events',
        desc: 'Design',
        img: 'img/works/PandG.png',
      },
      {
        id: 7,
        name: 'DEPED K12 Infographics',
        desc: 'Design',
        img: 'img/works/k12.png',
      },
      {
        id: 8,
        name: 'Famrun 2018',
        desc: 'Design',
        img: 'img/works/fun-run.png',
      },
    ],
  };
  render() {
    return (
      <div>
        <Sidebar />
      	<main id="main">
      		<div className="main-outer">
      			<div className="container-fluid">
      				<div className="row">
      					<div className="col-md-12">
      						<div id="works-grid">
      							<Test  projects={this.state.projects} />
      						</div>
      					</div>
      				</div>
      			</div>
      		</div>
      	</main>
      </div>
    );
  }
}

export default Home;
